509→  const resolveRepoRoot = async (workspaceRecord: import("surrealdb").RecordId<"workspace", string>): Promise<string> => {
510→    const [rows] = await wiringDeps.surreal.query<[Array<{ repo_path?: string }>]>(
511→      `SELECT repo_path FROM $ws;`,
512→      { ws: workspaceRecord },
