587→            intentContext.reasoning,
588→          );
589→        } catch (err) {
590→          return {
591→            ok: false,
592→            error: {
593→              code: "SESSION_ERROR",
594→              message: err instanceof Error ? err.message : "Failed to issue proxy token",
595→              httpStatus: 500,
596→            },
597→          };
598→        }
599→      }
600→
601→      const spawnAgent = createSpawnAgent(wiringDeps.queryFn);
602→      const result = await lifecycle.createOrchestratorSession({
603→        surreal: wiringDeps.surreal,
604→        shellExec: wiringDeps.shellExec,
605→        brainBaseUrl: wiringDeps.brainBaseUrl,
606→        brainIdentityId,
607→        brainEnv: brainAuthEnv,
608→        anthropicBaseUrl: proxyToken ? `${wiringDeps.brainBaseUrl}/proxy/llm/anthropic` : undefined,
609→        anthropicCustomHeaders: proxyToken ? `X-Brain-Auth: ${proxyToken}` : undefined,
610→        workspaceId,
611→        taskId,
612→        authToken,
613→        validateAssignment: guard.validateAssignment,
614→        createAgentSession: queries.createAgentSession,
615→        spawnAgent,
616→        adapter,
617→        sandboxAgentType: wiringDeps.sandboxAgentType,
618→      });
619→
620→      // Wire SSE stream + event iteration on success
621→      if (result.ok && wiringDeps.sseRegistry) {
622→        const { agentSessionId, streamId, sessionHandle } = result.value;
623→        wiringDeps.sseRegistry.registerMessage(streamId);
624→
625→        // Adapter path: wire sandbox event bridge
626→        if (sessionHandle && adapter) {
627→          const { createSandboxEventBridge } = await import("./sandbox-event-bridge");
628→          const bridge = createSandboxEventBridge(
629→            {
630→              emitEvent: wiringDeps.sseRegistry.emitEvent,
631→              updateLastEventAt: async (sid) => {
632→                const rec = new RecordId("agent_session", sid);
633→                await wiringDeps.surreal.update(rec).merge({
634→                  last_event_at: new Date(),
635→                });
636→              },
637→              notifyStallDetector: () => {
638→                // Stall detector integration deferred to later step
639→              },
640→            },
641→            streamId,
642→            agentSessionId,
643→          );
644→          sessionHandle.onEvent((event) => {
645→            bridge.handleEvent(event as import("./sandbox-event-bridge").SandboxEvent);
646→          });
647→        } else {
648→          // Legacy path: SDK message stream iteration
649→          const handle = lifecycle.getHandle(agentSessionId);
650→          if (handle) {
651→            const { RecordId } = await import("surrealdb");
652→            lifecycle.startEventIteration(
653→              {
654→                emitEvent: wiringDeps.sseRegistry.emitEvent,
655→                updateSessionStatus: async (sid, status, error) => {
656→                  const rec = new RecordId("agent_session", sid);
657→                  await wiringDeps.surreal.update(rec).merge({
658→                    orchestrator_status: status,
659→                    ...(error !== undefined ? { error_message: error } : {}),
660→                  });
661→                },
662→                updateLastEventAt: async (sid) => {
663→                  const rec = new RecordId("agent_session", sid);
664→                  await wiringDeps.surreal.update(rec).merge({
665→                    last_event_at: new Date(),
666→                  });
667→                },
668→                getSessionStatus: async (sid) => {
669→                  const rec = new RecordId("agent_session", sid);
670→                  const row = await wiringDeps.surreal.select(rec) as { orchestrator_status?: string } | undefined;
671→                  return (row?.orchestrator_status ?? "error") as import("./types").OrchestratorStatus;
672→                },
673→                startStallDetector: (sid, stId) =>
674→                  stallDetector.startStallDetector(
675→                    {
676→                      abortSession: async (abortSid) => {
677→                        const abortResult = await lifecycle.abortOrchestratorSession({
678→                          surreal: wiringDeps.surreal,
679→                          shellExec: wiringDeps.shellExec,
680→                          resolveRepoRoot,
681→                          sessionId: abortSid,
682→                          endAgentSession: queries.endAgentSession,
683→                        });
684→                        return abortResult;
685→                      },
686→                      createObservation: async () => {},
687→                      emitEvent: wiringDeps.sseRegistry!.emitEvent,
688→                    },
689→                    stallDetector.DEFAULT_STALL_CONFIG,
690→                    sid,
691→                    stId,
692→                  ),
693→              },
694→              handle.messages,
695→              streamId,
696→              agentSessionId,
697→            );
698→          }
699→        }
700→      }
701→
702→      return result;
703→    },
704→
705→    getSessionStatus: async (sessionId) => {
706→      const lifecycle = await lifecycleImport;
707→      return lifecycle.getOrchestratorSessionStatus({
708→        surreal: wiringDeps.surreal,
