740→    },
741→
742→    getReview: async (sessionId) => {
743→      const [lifecycle, worktreeManager] = await Promise.all([
744→        lifecycleImport,
745→        import("./worktree-manager"),
746→      ]);
747→      return lifecycle.getOrchestratorReview({
748→        surreal: wiringDeps.surreal,
749→        sessionId,
750→        resolveRepoRoot,
751→        getDiff: (repoRoot: string, branchName: string) =>
752→          worktreeManager.getDiff(wiringDeps.shellExec, repoRoot, branchName),
753→        getTaskTitle: async (taskId: string) => {
754→          const { RecordId } = await import("surrealdb");
755→          const taskRecord = new RecordId("task", taskId);
756→          const rows = (await wiringDeps.surreal.query(
757→            `SELECT title FROM $task;`,
758→            { task: taskRecord },
759→          )) as Array<Array<{ title: string }>>;
760→          return rows[0]?.[0]?.title ?? "";
761→        },
762→      });
763→    },
764→
765→    rejectSession: async (sessionId, feedback) => {
766→      const lifecycle = await lifecycleImport;
767→      return lifecycle.rejectOrchestratorSession({
768→        surreal: wiringDeps.surreal,
769→        sessionId,
770→        feedback,
771→      });
772→    },
773→
774→    sendPrompt: async (sessionId, text) => {
