 84→function normalizeTokens(value: string): Set<string> {
 85→  return new Set(
 86→    value
 87→      .toLowerCase()
 88→      .replace(/[^a-z0-9\s]/g, " ")
 89→      .split(/\s+/)
 90→      .map((t) => t.trim())
 91→      .filter((t) => t.length > 2),
