51→  | "TASK_NOT_FOUND"
52→  | "TASK_NOT_ASSIGNABLE"
53→  | "AGENT_ALREADY_ACTIVE"
54→  | "WORKSPACE_MISMATCH"
55→  | "MISSING_TASK_ID"
56→  | "REPO_PATH_REQUIRED";
57→
