  1→import { createOpenRouter } from "@openrouter/ai-sdk-provider";
  2→import { createOllama } from "ollama-ai-provider";
  3→import { wrapLanguageModel } from "ai";
  4→import { devToolsMiddleware } from "@ai-sdk/devtools";
  5→import { Surreal } from "surrealdb";
  6→import type { ServerConfig } from "./config";
  7→import { createAuth, type Auth } from "../auth/config";
  8→import { bootstrapSigningKeyFromSurreal, type AsSigningKey } from "../oauth/as-key-management";
  9→import { createMcpClientFactory, type McpClientFactory } from "../tool-registry/mcp-client";
 10→import type { SandboxAgentAdapter } from "../orchestrator/sandbox-adapter";
 11→
 12→const devtools = process.env.AI_DEVTOOLS === "1" ? devToolsMiddleware() : undefined;
 13→
 14→export async function createRuntimeDependencies(config: ServerConfig): Promise<{
 15→  surreal: Surreal;
 16→  analyticsSurreal: Surreal;
 17→  auth: Auth;
 18→  chatAgentModel: any;
 19→  extractionModel: any;
 20→  pmAgentModel: any;
 21→  analyticsAgentModel: any;
 22→  observerModel: any;
 23→  scorerModel: any;
 24→  asSigningKey: AsSigningKey;
 25→  mcpClientFactory: McpClientFactory;
 26→  sandboxAgentAdapter?: SandboxAgentAdapter;
 27→  destroySandbox?: () => Promise<void>;
 28→}> {
 29→  const surreal = new Surreal();
 30→  await surreal.connect(config.surrealUrl);
 31→  await surreal.signin({ username: config.surrealUsername, password: config.surrealPassword });
 32→  await surreal.use({ namespace: config.surrealNamespace, database: config.surrealDatabase });
 33→
 34→  const analyticsSurreal = new Surreal();
 35→  await analyticsSurreal.connect(config.surrealUrl);
 36→  await analyticsSurreal.signin({
 37→    namespace: config.surrealNamespace,
 38→    database: config.surrealDatabase,
 39→    username: "analytics",
 40→    password: "brain-analytics-readonly",
 41→  });
 42→  await analyticsSurreal.use({ namespace: config.surrealNamespace, database: config.surrealDatabase });
 43→
 44→  const wrap = (model: any) => devtools ? wrapLanguageModel({ model, middleware: devtools }) : model;
 45→
 46→  const { chatAgentModel, extractionModel, pmAgentModel, analyticsAgentModel, observerModel, scorerModel } =
 47→    config.inferenceProvider === "ollama"
 48→      ? createOllamaModels(config, wrap)
 49→      : createOpenRouterModels(config, wrap);
 50→
 51→  const auth = createAuth(surreal, {
 52→    betterAuthSecret: config.betterAuthSecret,
 53→    betterAuthUrl: config.betterAuthUrl,
 54→    githubClientId: config.githubClientId,
 55→    githubClientSecret: config.githubClientSecret,
 56→    selfHosted: config.selfHosted,
 57→  });
 58→
 59→  const asSigningKey = await bootstrapSigningKeyFromSurreal(surreal);
 60→  const mcpClientFactory = createMcpClientFactory();
 61→
 62→  // SandboxAgent SDK — start embedded server when enabled
 63→  // When orchestratorMockAgent is true, use mock adapter instead of real SDK
 64→  // (acceptance tests set both sandboxAgentEnabled + orchestratorMockAgent)
 65→  let sandboxAgentAdapter: SandboxAgentAdapter | undefined;
 66→  let destroySandbox: (() => Promise<void>) | undefined;
 67→  if (config.sandboxAgentEnabled && !config.orchestratorMockAgent) {
 68→    const { SandboxAgent: SandboxAgentClass } = await import("sandbox-agent");
 69→    const { local } = await import("sandbox-agent/local");
 70→    const { createSandboxAgentAdapter } = await import("../orchestrator/sandbox-adapter");
 71→    const sdk = await SandboxAgentClass.start({ sandbox: local() });
 72→    sandboxAgentAdapter = createSandboxAgentAdapter(sdk);
 73→    destroySandbox = () => sdk.destroySandbox();
 74→  } else if (config.sandboxAgentEnabled && config.orchestratorMockAgent) {
 75→    const { createMockAdapter } = await import("../orchestrator/sandbox-adapter");
 76→    sandboxAgentAdapter = createMockAdapter();
 77→  }
 78→
 79→  return {
 80→    surreal,
 81→    analyticsSurreal,
 82→    auth,
 83→    chatAgentModel,
 84→    extractionModel,
 85→    pmAgentModel,
 86→    analyticsAgentModel,
 87→    observerModel,
 88→    scorerModel,
 89→    asSigningKey,
 90→    mcpClientFactory,
 91→    sandboxAgentAdapter,
 92→    destroySandbox,
 93→  };
 94→}
 95→
 96→// ---------------------------------------------------------------------------
 97→// OpenRouter model factory
 98→// ---------------------------------------------------------------------------
 99→
100→function createOpenRouterModels(config: ServerConfig, wrap: (model: any) => any) {
101→  const openrouter = createOpenRouter({ apiKey: config.openRouterApiKey! });
102→  const withPlugins = (modelId: string, reasoning = true) =>
103→    wrap(openrouter(modelId, {
104→      plugins: [{ id: "response-healing" }],
105→      ...(reasoning && config.openRouterReasoning ? { extraBody: { reasoning: config.openRouterReasoning } } : {}),
106→    }));
107→
108→  return {
109→    chatAgentModel: withPlugins(config.chatAgentModelId),
110→    extractionModel: withPlugins(config.extractionModelId),
111→    pmAgentModel: withPlugins(config.pmAgentModelId),
112→    analyticsAgentModel: withPlugins(config.analyticsAgentModelId, false),
113→    observerModel: withPlugins(config.observerModelId),
114→    scorerModel: withPlugins(config.scorerModelId, false),
115→  };
116→}
117→
118→// ---------------------------------------------------------------------------
119→// Ollama model factory
120→// ---------------------------------------------------------------------------
121→
122→function createOllamaModels(config: ServerConfig, wrap: (model: any) => any) {
123→  const ollama = createOllama({ baseURL: `${config.ollamaBaseUrl}/api` });
124→
125→  return {
126→    chatAgentModel: wrap(ollama(config.chatAgentModelId)),
127→    extractionModel: wrap(ollama(config.extractionModelId)),
128→    pmAgentModel: wrap(ollama(config.pmAgentModelId)),
129→    analyticsAgentModel: wrap(ollama(config.analyticsAgentModelId)),
130→    observerModel: wrap(ollama(config.observerModelId)),
131→    scorerModel: wrap(ollama(config.scorerModelId)),
132→  };
133→}
