  1→import { RecordId, type Surreal } from "surrealdb";
  2→import type { ShellExec } from "./worktree-manager";
  3→import { removeWorktree } from "./worktree-manager";
  4→import type { AssignmentResult } from "./assignment-guard";
  5→import type { AssignmentError, OrchestratorStatus } from "./types";
  6→import { TERMINAL_ORCHESTRATOR_STATUSES } from "./types";
  7→import { startEventBridge, type SdkMessage } from "./event-bridge";
  8→import type { StreamEvent } from "../../shared/contracts";
  9→import type { StallDetectorHandle } from "./stall-detector";
 10→import { getIntentById, updateIntentStatus } from "../intent/intent-queries";
 11→import type { IntentStatus } from "../intent/types";
 12→import { log } from "../telemetry/logger";
 13→import type { SandboxAgentAdapter, SessionHandle } from "./sandbox-adapter";
 14→
 15→// ---------------------------------------------------------------------------
 16→// Types — exported for tests
 17→// ---------------------------------------------------------------------------
 18→
 19→export type SessionDeps = {
 20→  surreal: Surreal;
 21→  shellExec: ShellExec;
 22→  brainBaseUrl: string;
 23→};
 24→
 25→export type SessionErrorCode =
 26→  | "TASK_NOT_FOUND"
 27→  | "TASK_NOT_ASSIGNABLE"
 28→  | "AGENT_ALREADY_ACTIVE"
 29→  | "WORKSPACE_MISMATCH"
 30→  | "MISSING_TASK_ID"
 31→  | "WORKTREE_ERROR"
 32→  | "SESSION_NOT_FOUND"
 33→  | "SESSION_ERROR"
 34→  | "INTENT_NOT_AUTHORIZED";
 35→
 36→export type SessionError = {
 37→  code: SessionErrorCode;
 38→  message: string;
 39→  httpStatus: number;
 40→};
 41→
 42→export type SessionResult<T> =
 43→  | { ok: true; value: T }
 44→  | { ok: false; error: SessionError };
 45→
 46→export type OrchestratorSessionResult = SessionResult<{
 47→  agentSessionId: string;
 48→  streamId: string;
 49→  worktreeBranch: string;
 50→  sessionHandle?: SessionHandle;
 51→}>;
 52→
 53→export type SessionStatusResult = SessionResult<{
 54→  orchestratorStatus: OrchestratorStatus;
 55→  worktreeBranch?: string;
 56→  worktreePath?: string;
 57→  lastEventAt?: string;
 58→  startedAt?: string;
 59→  error?: string;
 60→}>;
 61→
 62→export type AbortSessionResult = SessionResult<{
 63→  aborted: boolean;
 64→  sessionId: string;
 65→}>;
 66→
 67→export type AcceptSessionResult = SessionResult<{
 68→  accepted: boolean;
 69→  sessionId: string;
 70→}>;
 71→
 72→export type ReviewResult = SessionResult<{
 73→  taskTitle: string;
 74→  diff: import("./worktree-manager").DiffResult;
 75→  session: {
 76→    orchestratorStatus: string;
 77→    worktreeBranch?: string;
 78→    startedAt?: string;
 79→    lastEventAt?: string;
 80→    toolCallCount?: number;
 81→    filesEdited?: number;
 82→  };
 83→}>;
 84→
 85→export type RejectSessionResult = SessionResult<{
 86→  rejected: boolean;
 87→  continuing: boolean;
 88→}>;
 89→
 90→export type PromptSessionResult = SessionResult<{
 91→  delivered: boolean;
 92→}>;
 93→
 94→// ---------------------------------------------------------------------------
 95→// Handle registry stubs — handleRegistry eliminated (ADR-075).
 96→// Session state lives in SurrealDB. Adapter wiring in step 02-03.
 97→// Stubs kept for backwards compatibility with existing call sites.
 98→// ---------------------------------------------------------------------------
 99→
100→/** @deprecated No-op — handleRegistry eliminated. */
101→export function clearHandleRegistry(): void {
102→  // No-op: module-level mutable singleton removed per AGENTS.md
103→}
104→
105→/** @deprecated Always returns undefined — handleRegistry eliminated. */
106→export function getHandle(_sessionId: string): AgentHandle | undefined {
107→  return undefined;
108→}
109→
110→// ---------------------------------------------------------------------------
111→// Event iteration — port (dependencies as function signatures)
112→// ---------------------------------------------------------------------------
113→
114→export type EventIterationDeps = {
115→  emitEvent: (streamId: string, event: StreamEvent) => void;
116→  updateSessionStatus: (
117→    sessionId: string,
118→    status: OrchestratorStatus,
119→    error?: string,
120→  ) => Promise<void>;
121→  updateLastEventAt: (sessionId: string) => Promise<void>;
122→  getSessionStatus: (sessionId: string) => Promise<OrchestratorStatus>;
123→  startStallDetector: (sessionId: string, streamId: string) => StallDetectorHandle;
124→};
125→
126→const TERMINAL_STATUSES: ReadonlySet<string> = new Set<string>(
127→  TERMINAL_ORCHESTRATOR_STATUSES,
128→);
129→
130→/**
131→ * Iterates the SDK message stream, forwarding messages through the event
132→ * bridge. Transitions session to "active" on first message, starts stall
133→ * detection, and stops on terminal status or error.
134→ *
135→ * Returns a Promise that resolves when iteration ends (for testing).
136→ * In production, this is launched fire-and-forget.
137→ */
138→export function startEventIteration(
139→  deps: EventIterationDeps,
140→  messageStream: AsyncIterable<unknown>,
141→  streamId: string,
142→  sessionId: string,
143→): Promise<void> {
144→  const stallDetector = deps.startStallDetector(sessionId, streamId);
145→
146→  const bridge = startEventBridge(
147→    {
148→      emitEvent: deps.emitEvent,
149→      updateLastEventAt: deps.updateLastEventAt,
150→    },
151→    streamId,
152→    sessionId,
153→    stallDetector,
154→  );
155→
156→  let firstMessageReceived = false;
157→  let messageCount = 0;
158→
159→  async function iterate(): Promise<void> {
160→    log.info("orchestrator.iteration", "Event iteration started, awaiting SDK messages", { sessionId, streamId });
161→    try {
162→      for await (const rawMessage of messageStream) {
163→        messageCount++;
164→        const msg = rawMessage as SdkMessage;
165→        log.info("orchestrator.iteration", `SDK message received (#${messageCount})`, {
166→          sessionId,
167→          messageType: msg.type,
168→          ...(msg.type === "result" ? { subtype: msg.subtype, ...(msg.subtype === "error" ? { error: msg.error } : {}) } : {}),
169→          ...(msg.type === "system" ? { subtype: msg.subtype } : {}),
170→        });
171→
172→        // Check if session has reached terminal status
173→        const currentStatus = await deps.getSessionStatus(sessionId);
174→        if (TERMINAL_STATUSES.has(currentStatus)) {
175→          log.info("orchestrator.iteration", "Stopping: session reached terminal status", { sessionId, currentStatus });
176→          break;
177→        }
178→
179→        // Transition to active on first message
180→        if (!firstMessageReceived) {
181→          firstMessageReceived = true;
182→          await deps.updateSessionStatus(sessionId, "active");
183→        }
184→
185→        // Forward through event bridge (transform + emit + stall detection)
186→        bridge.handleMessage(msg);
187→      }
188→      log.info("orchestrator.iteration", "Event iteration ended normally", { sessionId, messageCount });
189→      // Transition to idle when stream ends normally and agent produced output
190→      if (firstMessageReceived) {
191→        const finalStatus = await deps.getSessionStatus(sessionId);
192→        if (!TERMINAL_STATUSES.has(finalStatus)) {
193→          await deps.updateSessionStatus(sessionId, "idle");
194→        }
195→      }
196→    } catch (err) {
197→      const errorMessage = err instanceof Error ? err.message : String(err);
198→      log.error("orchestrator.iteration", "Agent message stream error", err, { sessionId, streamId });
199→      await deps.updateSessionStatus(sessionId, "error", errorMessage);
200→    } finally {
201→      if (!firstMessageReceived) {
202→        log.warn("orchestrator.iteration", "Agent stream ended with zero messages", { sessionId, streamId });
203→      }
204→      bridge.stop();
205→    }
206→  }
207→
208→  return iterate();
209→}
210→
211→// ---------------------------------------------------------------------------
212→// Pure helpers
213→// ---------------------------------------------------------------------------
214→
215→export function pickDefined<T extends Record<string, unknown>>(obj: T): Partial<T> {
216→  const result: Record<string, unknown> = {};
217→  for (const [key, value] of Object.entries(obj)) {
218→    if (value !== undefined) {
219→      result[key] = value;
220→    }
221→  }
222→  return result as Partial<T>;
223→}
224→
225→function sessionNotFound(sessionId: string): SessionError {
226→  return {
227→    code: "SESSION_NOT_FOUND",
228→    message: `Session not found: ${sessionId}`,
229→    httpStatus: 404,
230→  };
231→}
232→
233→function worktreeError(message: string): SessionError {
234→  return {
235→    code: "WORKTREE_ERROR",
236→    message,
237→    httpStatus: 500,
238→  };
239→}
240→
241→function fromAssignmentError(error: AssignmentError): SessionError {
242→  return {
243→    code: error.code as SessionErrorCode,
244→    message: error.message,
245→    httpStatus: error.httpStatus,
246→  };
247→}
248→
249→// ---------------------------------------------------------------------------
250→// Session row shape (DB query result)
251→// ---------------------------------------------------------------------------
252→
253→type SessionRow = {
254→  id: RecordId<"agent_session", string>;
255→  orchestrator_status?: string;
256→  worktree_branch?: string;
257→  worktree_path?: string;
258→  started_at?: string;
259→  last_event_at?: string;
260→  task_id?: RecordId<"task", string>;
261→  workspace?: RecordId<"workspace", string>;
262→  error_message?: string;
263→  external_session_id?: string;
264→  session_type?: string;
265→};
266→
267→type SessionLookup =
268→  | { ok: true; session: SessionRow; record: RecordId<"agent_session", string>; status: OrchestratorStatus }
269→  | { ok: false; error: SessionError };
270→
271→async function lookupSession(
272→  surreal: Surreal,
273→  sessionId: string,
274→): Promise<SessionLookup> {
275→  const record = new RecordId("agent_session", sessionId);
276→  const session = await surreal.select<SessionRow>(record);
277→  if (!session) {
278→    return { ok: false, error: sessionNotFound(sessionId) };
279→  }
280→  if (!session.orchestrator_status) {
281→    throw new Error(`agent_session ${sessionId} missing orchestrator_status — data corruption`);
282→  }
283→  const status = session.orchestrator_status as OrchestratorStatus;
284→  return { ok: true, session, record, status };
285→}
286→
287→function requireWorkspace(session: SessionRow, sessionId: string): RecordId<"workspace", string> {
288→  if (!session.workspace) {
289→    throw new Error(`agent_session ${sessionId} missing workspace — data corruption`);
290→  }
291→  return session.workspace as RecordId<"workspace", string>;
292→}
293→
294→function generateStreamId(sessionId: string): string {
295→  return `stream-${sessionId}`;
296→}
297→
298→// ---------------------------------------------------------------------------
299→// createOrchestratorSession
300→// ---------------------------------------------------------------------------
301→
302→type CreateSessionInput = {
303→  surreal: Surreal;
304→  shellExec: ShellExec;
305→  brainBaseUrl: string;
306→  workspaceId: string;
307→  taskId: string;
308→  intentId?: string;
309→  authToken?: string;
310→  adapter: SandboxAgentAdapter;
311→  sandboxAgentType?: string;
312→  validateAssignment: (
313→    surreal: Surreal,
314→    workspaceId: string,
315→    taskId: string,
316→  ) => Promise<AssignmentResult>;
317→  createAgentSession: (input: {
318→    surreal: Surreal;
319→    agent: string;
320→    workspaceRecord: RecordId<"workspace", string>;
321→    taskId?: string;
322→  }) => Promise<{ session_id: string }>;
323→};
324→
325→export async function createOrchestratorSession(
326→  input: CreateSessionInput,
327→): Promise<OrchestratorSessionResult> {
328→  // 0. Intent authorization gate (optional — backwards compatible)
329→  if (input.intentId) {
330→    const gateResult = await checkIntentAuthorization(input.surreal, input.intentId, input.workspaceId);
331→    if (!gateResult.ok) {
332→      return { ok: false, error: gateResult.error };
333→    }
334→  }
335→
336→  // 1. Validate assignment eligibility
337→  const assignmentResult = await input.validateAssignment(
338→    input.surreal,
339→    input.workspaceId,
340→    input.taskId,
341→  );
342→
343→  if (!assignmentResult.ok) {
344→    return { ok: false, error: fromAssignmentError(assignmentResult.error) };
345→  }
346→
347→  const { validation } = assignmentResult;
348→
349→  return createSessionViaAdapter(input, validation);
350→}
351→
352→// ---------------------------------------------------------------------------
353→// Intent authorization helpers
354→// ---------------------------------------------------------------------------
355→
356→async function checkIntentAuthorization(
357→  surreal: Surreal,
358→  intentId: string,
359→  workspaceId: string,
360→): Promise<SessionResult<void>> {
361→  const intent = await getIntentById(surreal, intentId);
362→  if (!intent) {
363→    return {
364→      ok: false,
365→      error: {
366→        code: "INTENT_NOT_AUTHORIZED",
367→        message: `Intent ${intentId} not found`,
368→        httpStatus: 404,
369→      },
370→    };
371→  }
372→
373→  // Validate workspace scope: intent must belong to the session's workspace
374→  const intentWorkspaceId = intent.workspace.id as string;
375→  if (intentWorkspaceId !== workspaceId) {
376→    return {
377→      ok: false,
378→      error: {
379→        code: "WORKSPACE_MISMATCH",
380→        message: `Intent ${intentId} belongs to workspace "${intentWorkspaceId}", not "${workspaceId}"`,
381→        httpStatus: 403,
382→      },
383→    };
384→  }
385→
386→  const status = intent.status as IntentStatus;
387→  if (status !== "authorized") {
388→    return {
389→      ok: false,
390→      error: {
391→        code: "INTENT_NOT_AUTHORIZED",
392→        message: `Intent ${intentId} has status "${status}", expected "authorized"`,
393→        httpStatus: 403,
394→      },
395→    };
396→  }
397→
398→  return { ok: true, value: undefined as void };
399→}
400→
401→async function transitionIntentToExecuting(
402→  surreal: Surreal,
403→  intentId: string,
404→  sessionRecord: RecordId<"agent_session", string>,
405→): Promise<void> {
406→  await updateIntentStatus(surreal, intentId, "executing");
407→
408→  const intentRecord = new RecordId("intent", intentId);
409→  // NOTE: `$session` is a SurrealDB protected variable — use `$sess` instead
410→  await surreal.query(
411→    "RELATE $intent->gates->$sess SET created_at = time::now();",
412→    { intent: intentRecord, sess: sessionRecord },
413→  );
414→
415→  log.info("orchestrator.intent-gate", "Intent transitioned to executing with gates relation", {
416→    intentId,
417→    sessionId: sessionRecord.id as string,
418→  });
419→}
420→
421→// ---------------------------------------------------------------------------
422→// Adapter-based session creation
423→// ---------------------------------------------------------------------------
424→
425→async function createSessionViaAdapter(
426→  input: CreateSessionInput,
427→  validation: import("./types").AssignmentValidation,
428→): Promise<OrchestratorSessionResult> {
429→  const adapter = input.adapter!;
430→
431→  // 1. Create agent_session record
432→  const { session_id: agentSessionId } = await input.createAgentSession({
433→    surreal: input.surreal,
434→    agent: "claude",
435→    workspaceRecord: validation.workspaceRecord,
436→    taskId: input.taskId,
437→  });
438→
439→  const streamId = generateStreamId(agentSessionId);
440→
441→  // 2. Create session via adapter
442→  let handle: SessionHandle;
443→  try {
444→    handle = await adapter.createSession({
445→      agent: input.sandboxAgentType ?? "claude",
446→      cwd: validation.repoPath,
447→    });
448→  } catch (err) {
449→    // Rollback: delete agent_session on adapter failure
450→    const sessionRecord = new RecordId("agent_session", agentSessionId);
451→    await input.surreal.delete(sessionRecord);
452→    return {
453→      ok: false,
454→      error: worktreeError(`Failed to create sandbox session: ${err instanceof Error ? err.message : String(err)}`),
455→    };
456→  }
457→
458→  // 3. Update agent_session with sandbox fields
459→  const sessionRecord = new RecordId("agent_session", agentSessionId);
460→  await input.surreal.update(sessionRecord).merge({
461→    orchestrator_status: "spawning" as OrchestratorStatus,
462→    stream_id: streamId,
463→    session_type: "sandbox_agent",
464→    provider: "local",
465→    external_session_id: handle.id,
466→  });
467→
468→  // 4. Transition intent to executing
469→  if (input.intentId) {
470→    await transitionIntentToExecuting(input.surreal, input.intentId, sessionRecord);
471→  }
472→
473→  return {
474→    ok: true,
475→    value: {
476→      agentSessionId,
477→      streamId,
478→      worktreeBranch: `sandbox-${agentSessionId}`,
479→      sessionHandle: handle,
480→    },
481→  };
482→}
483→
484→// ---------------------------------------------------------------------------
485→// getOrchestratorSessionStatus
486→// ---------------------------------------------------------------------------
487→
488→type GetStatusInput = {
489→  surreal: Surreal;
490→  sessionId: string;
491→};
492→
493→export async function getOrchestratorSessionStatus(
494→  input: GetStatusInput,
495→): Promise<SessionStatusResult> {
496→  const lookup = await lookupSession(input.surreal, input.sessionId);
497→  if (!lookup.ok) {
498→    return { ok: false, error: lookup.error };
499→  }
500→  const { session } = lookup;
501→
502→  return {
503→    ok: true,
504→    value: {
505→      orchestratorStatus: lookup.status,
506→      ...pickDefined({
507→        worktreeBranch: session.worktree_branch,
508→        worktreePath: session.worktree_path,
509→        startedAt: session.started_at,
510→        lastEventAt: session.last_event_at,
511→        error: session.error_message,
512→      }),
513→    },
514→  };
515→}
516→
517→// ---------------------------------------------------------------------------
518→// abortOrchestratorSession
519→// ---------------------------------------------------------------------------
520→
521→type AbortSessionInput = {
522→  surreal: Surreal;
523→  shellExec: ShellExec;
524→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
525→  sessionId: string;
526→  adapter?: SandboxAgentAdapter;
527→  endAgentSession: (input: {
528→    surreal: Surreal;
529→    workspaceRecord: RecordId<"workspace", string>;
530→    sessionId: string;
531→    summary: string;
532→  }) => Promise<{ session_id: string; ended: boolean }>;
533→};
534→
535→export async function abortOrchestratorSession(
536→  input: AbortSessionInput,
537→): Promise<AbortSessionResult> {
538→  const lookup = await lookupSession(input.surreal, input.sessionId);
539→  if (!lookup.ok) {
540→    return { ok: false, error: lookup.error };
541→  }
542→  const { session, record: sessionRecord } = lookup;
543→
544→  // 1. Abort the agent process via adapter if available
545→  if (input.adapter && session.external_session_id) {
546→    try {
547→      await input.adapter.destroySession(session.external_session_id);
548→    } catch (err) {
549→      log.warn("orchestrator.abort", "Failed to destroy sandbox session", {
550→        sessionId: input.sessionId,
551→        externalSessionId: session.external_session_id,
552→        error: String(err),
553→      });
554→    }
555→  }
556→
557→  // 2. Update orchestrator_status to aborted
558→  await input.surreal.update(sessionRecord).merge({
559→    orchestrator_status: "aborted" as OrchestratorStatus,
560→  });
561→
562→  const workspaceRecord = requireWorkspace(session, input.sessionId);
563→
564→  // 3. Remove worktree if branch name exists
565→  if (session.worktree_branch) {
566→    const repoRoot = await input.resolveRepoRoot(workspaceRecord);
567→    await removeWorktree(input.shellExec, repoRoot, session.worktree_branch);
568→  }
569→
570→  // 4. Return task to ready
571→  if (session.task_id) {
572→    await input.surreal.update(session.task_id).merge({
573→      status: "ready",
574→      updated_at: new Date(),
575→    });
576→  }
577→
578→  // 5. End the agent session
579→  await input.endAgentSession({
580→    surreal: input.surreal,
581→    workspaceRecord,
