594→
595→// ---------------------------------------------------------------------------
596→// acceptOrchestratorSession
597→// ---------------------------------------------------------------------------
598→
599→type AcceptSessionInput = {
600→  surreal: Surreal;
601→  sessionId: string;
602→  summary: string;
603→  endAgentSession: (input: {
604→    surreal: Surreal;
605→    workspaceRecord: RecordId<"workspace", string>;
606→    sessionId: string;
607→    summary: string;
