650→// ---------------------------------------------------------------------------
651→// State guard helpers
652→// ---------------------------------------------------------------------------
653→
654→const REVIEWABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
655→const REJECTABLE_STATUSES = new Set<OrchestratorStatus>(["idle"]);
656→const ACCEPTABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
657→const PROMPTABLE_STATUSES = new Set<OrchestratorStatus>(["spawning", "active", "idle"]);
658→
659→function sessionStateConflict(sessionId: string, currentStatus: string, action: string): SessionError {
660→  return {
661→    code: "SESSION_ERROR",
662→    message: `Cannot ${action} session ${sessionId}: current status is ${currentStatus}`,
663→    httpStatus: 409,
664→  };
665→}
