675→// ---------------------------------------------------------------------------
676→// getOrchestratorReview
677→// ---------------------------------------------------------------------------
678→
679→type GetReviewInput = {
680→  surreal: Surreal;
681→  sessionId: string;
682→  getDiff: (repoRoot: string, branchName: string) => Promise<import("./worktree-manager").WorktreeResult<import("./worktree-manager").DiffResult>>;
683→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
684→  getTaskTitle: (taskId: string) => Promise<string>;
685→};
686→
687→export async function getOrchestratorReview(
688→  input: GetReviewInput,
689→): Promise<ReviewResult> {
690→  const lookup = await lookupSession(input.surreal, input.sessionId);
691→  if (!lookup.ok) {
692→    return { ok: false, error: lookup.error };
693→  }
694→  const { session, status } = lookup;
695→
696→  if (status === "aborted") {
697→    return { ok: false, error: sessionAborted(input.sessionId) };
698→  }
699→
700→  if (!REVIEWABLE_STATUSES.has(status)) {
701→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "review") };
702→  }
703→
704→  // Get diff from the branch
705→  const branchName = session.worktree_branch ?? "";
706→  const workspaceRecord = requireWorkspace(session, input.sessionId);
707→  const repoRoot = await input.resolveRepoRoot(workspaceRecord);
708→  const diffResult = await input.getDiff(repoRoot, branchName);
709→
710→  const diff = diffResult.ok
711→    ? diffResult.value
712→    : { files: [], rawDiff: "", stats: { filesChanged: 0, insertions: 0, deletions: 0 } };
713→
714→  // Get task title
715→  const taskId = session.task_id ? session.task_id.id : "";
716→  const taskTitle = taskId ? await input.getTaskTitle(taskId) : "";
717→
718→  return {
719→    ok: true,
720→    value: {
721→      taskTitle,
722→      diff,
723→      session: {
724→        orchestratorStatus: status,
725→        ...pickDefined({
726→          worktreeBranch: session.worktree_branch,
727→          startedAt: session.started_at,
728→          lastEventAt: session.last_event_at,
729→        }),
730→      },
731→    },
732→  };
733→}
734→
735→// ---------------------------------------------------------------------------
736→// rejectOrchestratorSession
737→// ---------------------------------------------------------------------------
738→
739→type RejectSessionInput = {
740→  surreal: Surreal;
741→  sessionId: string;
742→  feedback: string;
743→};
744→
745→export async function rejectOrchestratorSession(
746→  input: RejectSessionInput,
747→): Promise<RejectSessionResult> {
748→  const lookup = await lookupSession(input.surreal, input.sessionId);
749→  if (!lookup.ok) {
750→    return { ok: false, error: lookup.error };
751→  }
752→  const { session, record: sessionRecord, status } = lookup;
753→
754→  if (!REJECTABLE_STATUSES.has(status)) {
755→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "reject") };
756→  }
757→
758→  // 1. Update session status to active (agent resumes work)
759→  await input.surreal.update(sessionRecord).merge({
760→    orchestrator_status: "active" as OrchestratorStatus,
761→    last_feedback: input.feedback,
762→  });
763→
764→  // 2. Return task to in_progress
765→  if (session.task_id) {
766→    await input.surreal.update(session.task_id).merge({
767→      status: "in_progress",
768→      updated_at: new Date(),
769→    });
770→  }
771→
772→  return {
773→    ok: true,
774→    value: {
775→      rejected: true,
776→      continuing: true,
777→    },
778→  };
779→}
780→
781→// ---------------------------------------------------------------------------
782→// sendSessionPrompt
783→// ---------------------------------------------------------------------------
784→
785→type SendPromptInput = {
786→  surreal: Surreal;
787→  sessionId: string;
788→  text: string;
789→  adapter?: SandboxAgentAdapter;
790→};
791→
792→export async function sendSessionPrompt(
793→  input: SendPromptInput,
794→): Promise<PromptSessionResult> {
795→  const lookup = await lookupSession(input.surreal, input.sessionId);
796→  if (!lookup.ok) {
797→    return { ok: false, error: lookup.error };
798→  }
799→  const { session, status } = lookup;
800→
801→  if (!PROMPTABLE_STATUSES.has(status)) {
802→    // Terminal sessions return 404 (session is "gone"), non-terminal return 409 (conflict)
803→    if (TERMINAL_STATUSES.has(status)) {
804→      return { ok: false, error: sessionNotFound(input.sessionId) };
805→    }
806→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "prompt") };
807→  }
808→
809→  // ── Adapter path: delegate to SandboxAgentAdapter ──
810→  if (input.adapter && session.external_session_id) {
811→    try {
812→      const handle = await input.adapter.resumeSession(session.external_session_id);
813→      await handle.prompt([{ type: "text", text: input.text }]);
814→      return { ok: true, value: { delivered: true } };
815→    } catch (err) {
816→      return {
817→        ok: false,
818→        error: {
819→          code: "SESSION_ERROR",
820→          message: `Failed to deliver prompt: ${err instanceof Error ? err.message : String(err)}`,
821→          httpStatus: 500,
822→        },
823→      };
824→    }
825→  }
826→
827→  // ── Legacy path: Agent SDK does not support follow-up prompts ──
828→  return {
829→    ok: false,
830→    error: {
831→      code: "SESSION_ERROR",
832→      message: `Follow-up prompts are not supported with the Agent SDK. Session ${input.sessionId} runs a single query() conversation.`,
833→      httpStatus: 409,
834→    },
835→  };
836→}
